import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { ChevronLeft, ChevronRight, Trash2, X, Save } from 'lucide-react';

const Listagem = () => {
  const [despesas, setDespesas] = useState([]);
  const [cartoes, setCartoes] = useState([]);
  const [usuarios, setUsuarios] = useState([]);
  const [perfilLogado, setPerfilLogado] = useState(null);
  const [itemParaEditar, setItemParaEditar] = useState(null);
  const [filtroData, setFiltroData] = useState({ mes: new Date().getMonth(), ano: new Date().getFullYear() });

  const mesesNominais = ["Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"];

  useEffect(() => {
    async function init() {
      const { data: { user } } = await supabase.auth.getUser();
      const { data: p } = await supabase.from('profiles').select('*').eq('id', user.id).single();
      setPerfilLogado(p);

      const { data: c } = await supabase.from('cartoes').select('nome').order('nome');
      setCartoes(c || []);

      const { data: u } = await supabase.from('profiles').select('id, nome').order('nome');
      setUsuarios(u || []);

      fetchDespesas(p);
    }
    init();
  }, [filtroData]);

  async function fetchDespesas(p) {
    const { data, error } = await supabase.from('compras').select('*, profiles(nome)');
    if (error) return;

    const projetadas = [];
    data.forEach(item => {
      // Filtragem: Proprietário vê tudo. Comum vê apenas se user_id bater OU se o texto 'responsavel' bater com o nome dele
      const ehDonoID = item.user_id === p.id;
      const ehDonoNome = item.responsavel?.toLowerCase() === p.nome?.toLowerCase();
      const podeVer = p.tipo_usuario === 'proprietario' || ehDonoID || ehDonoNome;

      if (podeVer) {
        const numParcelas = item.num_parcelas || 1;
        for (let i = 0; i < numParcelas; i++) {
          const dataCompra = new Date(item.data_compra + 'T12:00:00');
          const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);
          
          if (dataParcela.getMonth() === filtroData.mes && dataParcela.getFullYear() === filtroData.ano) {
            projetadas.push({
              ...item,
              parcelaAtual: i + 1,
              valorParcela: parseFloat(item.valor_total) / numParcelas,
              nomeExibicao: item.profiles?.nome || item.responsavel || 'Desconhecido'
            });
          }
        }
      }
    });
    setDespesas(projetadas.sort((a,b) => new Date(b.data_compra) - new Date(a.data_compra)));
  }

  const handleUpdate = async (e) => {
    e.preventDefault();
    const { error } = await supabase.from('compras').update({
      descricao: itemParaEditar.descricao,
      loja: itemParaEditar.loja,
      user_id: itemParaEditar.user_id, // Pode ser null se for antigo
      valor_total: parseFloat(itemParaEditar.valor_total),
      cartao: itemParaEditar.cartao
    }).eq('id', itemParaEditar.id);

    if (!error) { setItemParaEditar(null); fetchDespesas(perfilLogado); }
  };

  const mudarMes = (d) => {
    let m = filtroData.mes + d;
    let a = filtroData.ano;
    if (m < 0) { m = 11; a--; } else if (m > 11) { m = 0; a++; }
    setFiltroData({ mes: m, ano: a });
  };

  return (
    <div className="fade-in" style={{ padding: '20px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
        <h2>Extrato</h2>
        <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
          <button onClick={() => mudarMes(-1)} className="btn-nav"> <ChevronLeft /> </button>
          <span>{mesesNominais[filtroData.mes]} / {filtroData.ano}</span>
          <button onClick={() => mudarMes(1)} className="btn-nav"> <ChevronRight /> </button>
        </div>
      </div>

      <div className="card" style={{ overflowX: 'auto', padding: 0 }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: '#f8fafc', textAlign: 'left' }}>
              <th style={pStyle}>Data</th>
              <th style={pStyle}>Responsável</th>
              <th style={pStyle}>Descrição</th>
              <th style={pStyle}>Parcela</th>
              <th style={{...pStyle, textAlign: 'right'}}>Valor</th>
            </tr>
          </thead>
          <tbody>
            {despesas.map((item, idx) => (
              <tr key={idx} onClick={() => perfilLogado.tipo_usuario === 'proprietario' && setItemParaEditar(item)} style={{ borderTop: '1px solid #eee', cursor: 'pointer' }}>
                <td style={pStyle}>{new Date(item.data_compra + 'T12:00:00').toLocaleDateString('pt-BR', {day:'2-digit', month:'2-digit'})}</td>
                <td style={pStyle}><b>{item.nomeExibicao}</b></td>
                <td style={pStyle}>{item.descricao}</td>
                <td style={pStyle}>{item.parcelado ? `${item.parcelaAtual}/${item.num_parcelas}` : 'À Vista'}</td>
                <td style={{...pStyle, textAlign: 'right'}}>R$ {item.valorParcela.toLocaleString('pt-BR', {minimumFractionDigits:2})}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {itemParaEditar && (
        <div className="modal-overlay">
          <div className="modal-content">
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h3>Editar Lançamento</h3>
              <X onClick={() => setItemParaEditar(null)} style={{ cursor: 'pointer' }} />
            </div>
            <form onSubmit={handleUpdate} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
              <label>Responsável</label>
              <select className="form-control" value={itemParaEditar.user_id || ''} onChange={e => setItemParaEditar({...itemParaEditar, user_id: e.target.value})}>
                <option value="">(Manter original: {itemParaEditar.responsavel})</option>
                {usuarios.map(u => <option key={u.id} value={u.id}>{u.nome}</option>)}
              </select>
              <input className="form-control" value={itemParaEditar.descricao} onChange={e => setItemParaEditar({...itemParaEditar, descricao: e.target.value})} />
              <input className="form-control" type="number" value={itemParaEditar.valor_total} onChange={e => setItemParaEditar({...itemParaEditar, valor_total: e.target.value})} />
              <button type="submit" className="btn-primary">Salvar</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const pStyle = { padding: '15px' };

export default Listagem;
